ALTER TABLE `shipping_ports_ecm`.`customer`.`contact_person` ADD CONSTRAINT `fk_customer_contact_person_port_community_participant_id` FOREIGN KEY (`port_community_participant_id`) REFERENCES `shipping_ports_ecm`.`customer`.`port_community_participant`(`port_community_participant_id`);
